export function getSpotById(id: string): WorldSpot | undefined {
  return WORLD_SPOTS.find(s => s.id === id);
}

export function getSpotsByCountry(country: string): WorldSpot[] {
  return WORLD_SPOTS.filter(s => s.country === country);
}

export function getSpotsByContinent(continent: string): WorldSpot[] {
  return WORLD_SPOTS.filter(s => s.continent === continent);
}

export function getSpotsByDifficulty(difficulty: WorldSpot['difficulty']): WorldSpot[] {
  return WORLD_SPOTS.filter(s => s.difficulty === difficulty);
}

export function searchSpots(query: string): WorldSpot[] {
  const q = query.toLowerCase();
  return WORLD_SPOTS.filter(s =>
    s.name.toLowerCase().includes(q) ||
    s.country.toLowerCase().includes(q) ||
    s.region.toLowerCase().includes(q) ||
    s.species.some(sp => sp.toLowerCase().includes(q))
  );
}

export function getFeaturedSpots(): WorldSpot[] {
  return WORLD_SPOTS.filter(s => s.rating >= 4.8).slice(0, 10);
}
